class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _popen_priority_kwargs(self) -> dict[str, t.Any]:
        if self.process_priority not in _EDITOR_PROCESS_PRIORITIES:
            return {}

        if WIN:
            import subprocess

            windows_priority_classes = {
                "low": subprocess.IDLE_PRIORITY_CLASS,
                "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,
                "normal": subprocess.NORMAL_PRIORITY_CLASS,
                "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,
                "high": subprocess.HIGH_PRIORITY_CLASS,
            }
            return {"creationflags": windows_priority_classes[self.process_priority]}

        unix_niceness = {
            "low": 10,
            "below_normal": 5,
            "normal": 0,
            "above_normal": -5,
            "high": -10,
        }
        niceness = unix_niceness[self.process_priority]

        def _set_niceness() -> None:
            with contextlib.suppress(OSError):
                os.nice(niceness)

        return {"preexec_fn": _set_niceness}

    def edit_files(self, filenames: cabc.Iterable[str]) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        quoted_filenames = " ".join(f'"{filename}"' for filename in filenames)

        try:
            c = subprocess.Popen(
                f"{editor} {quoted_filenames}",
                env=environ,
                shell=True,
                **self._popen_priority_kwargs(),
            )
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

